import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, HelpCircle, LayoutDashboard, Users, BarChart3, MessageCircle, AlertCircle
} from 'lucide-react';

const Login = () => {
  // --- STATE SYSTEM ---
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [userRequests, setUserRequests] = useState([]); 
  const [adminStats, setAdminStats] = useState({ usersCount: 0, appsCount: 0, approvedCount: 0 });
  const [adminRequests, setAdminRequests] = useState([]);
  const [showModal, setShowModal] = useState(false);
  const [selectedFileName, setSelectedFileName] = useState("");
  const [loading, setLoading] = useState(false);

  // --- 1. DATA INITIALIZATION ---
  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    if (token) {
      if (role === 'admin') {
        setView('admin-dashboard');
        loadAdminPanel();
      } else {
        setView('dashboard');
        loadUserPanel(localStorage.getItem('userId'));
      }
    }
  }, []);

  const loadUserPanel = async (userId) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${userId}`);
      setUserRequests(Array.isArray(res.data) ? res.data : []);
    } catch (e) { setUserRequests([]); }
  };

  const loadAdminPanel = async () => {
    try {
      setLoading(true);
      const [stats, reqs] = await Promise.all([
        axios.get('http://localhost:5000/api/admin/stats'),
        axios.get('http://localhost:5000/api/admin/requests')
      ]);
      setAdminStats(stats.data);
      setAdminRequests(Array.isArray(reqs.data) ? reqs.data : []);
    } catch (e) { console.error("Admin Load Error"); }
    finally { setLoading(false); }
  };

  // --- 2. AUTHENTICATION (AUTHENTICATION SYSTEM) ---
  const handleAuth = async (e) => {
    e.preventDefault();
    setLoading(true);
    const mode = (view === 'admin-login' || view === 'login') ? 'login' : 'register';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        const { token, user } = res.data;
        localStorage.setItem('token', token);
        localStorage.setItem('userRole', user.role);
        localStorage.setItem('userId', user._id);
        localStorage.setItem('userName', user.name);
        
        if (user.role === 'admin') {
          setView('admin-dashboard');
          await loadAdminPanel();
        } else {
          setView('dashboard');
          await loadUserPanel(user._id);
        }
      } else {
        alert("Registration Successful!");
        setView('login');
      }
    } catch (err) { alert(err.response?.data?.msg || "Action Failed"); }
    finally { setLoading(false); }
  };

  // --- 3. ADMIN OPERATIONS (STATUS UPDATES) ---
  const updateRequestStatus = async (id, status) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/requests/${id}`, { status });
      loadAdminPanel();
    } catch (e) { alert("Status Update Failed"); }
  };

  // --- 4. USER OPERATIONS (FILE HANDLING) ---
  const handleFileUpload = async () => {
    try {
      const [fileHandle] = await window.showOpenFilePicker();
      const file = await fileHandle.getFile();
      setSelectedFileName(file.name);
    } catch (e) {}
  };

  const handleApplicationSubmit = async (e) => {
    e.preventDefault();
    const body = {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "manual_upload.pdf"
    };
    try {
      await axios.post('http://localhost:5000/api/requests/submit', body);
      setShowModal(false);
      setSelectedFileName("");
      loadUserPanel(localStorage.getItem('userId'));
      setActiveTab('tracking');
    } catch (e) { alert("Submission Error"); }
  };

  // ==========================================
  // VIEW: LANDING & AUTH
  // ==========================================
  if (['landing', 'login', 'register', 'admin-login'].includes(view)) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full">
            <div className="mb-12">
               <div className="inline-block bg-blue-600 p-4 rounded-3xl mb-4 text-white shadow-xl shadow-blue-200"><ShieldCheck size={48} /></div>
               <h1 className="text-5xl font-black text-slate-900 tracking-tight italic uppercase italic">QUAD SOLUTIONS</h1>
               <p className="text-slate-500 font-medium">Professional Credentialing Portal</p>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl hover:border-blue-600 border-2 border-transparent transition text-left cursor-pointer"><UserPlus className="text-blue-600 mb-6" size={32} /><h2 className="text-2xl font-black">New Providers</h2><div className="text-blue-600 font-bold mt-2">Get Started <ArrowRight className="inline ml-2" size={16}/></div></div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl hover:border-blue-400 border-2 border-transparent transition text-left cursor-pointer"><LogIn className="text-blue-400 mb-6" size={32} /><h2 className="text-2xl font-black">Existing Clients</h2><div className="text-blue-400 font-bold mt-2">Sign In <ArrowRight className="inline ml-2" size={16}/></div></div>
            </div>
            <footer className="mt-20"><button onClick={() => setView('admin-login')} className="bg-white border px-6 py-2 rounded-full text-[10px] font-black uppercase text-slate-300 hover:text-blue-600 transition tracking-widest"><ShieldCheck className="inline mr-2" size={14}/> Internal Admin Access</button></footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 font-bold">Back</button>
            <h2 className="text-3xl font-black mb-8 italic uppercase">{view.replace('-', ' ')}</h2>
            <form onSubmit={handleAuth} className="space-y-4">
              {view === 'register' && <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, password: e.target.value})} required />
              <button disabled={loading} className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-lg">
                {loading ? "Authenticating..." : "Continue"}
              </button>
            </form>
          </div>
        )}
      </div>
    );
  }

  // ==========================================
  // VIEW: ADMIN PANEL (ROLE-BASED ACCESS)
  // ==========================================
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white">
        <nav className="p-6 border-b border-slate-900 flex justify-between items-center bg-black/40 backdrop-blur-xl">
          <h1 className="text-xl font-black text-blue-500 uppercase italic flex items-center gap-2"><LayoutDashboard/> Admin Infrastructure</h1>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600/10 text-red-500 border border-red-500/20 px-6 py-2 rounded-xl font-black">Secure Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-6 mb-12">
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Active Providers</p><h4 className="text-4xl font-black">{adminStats.usersCount}</h4></div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-yellow-500"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Global Requests</p><h4 className="text-4xl font-black text-yellow-500">{adminStats.appsCount}</h4></div>
              <div className="bg-slate-900 p-8 rounded-3xl border border-slate-800 border-l-4 border-l-green-500"><p className="text-slate-500 text-[10px] font-black uppercase tracking-widest">Approved Apps</p><h4 className="text-4xl font-black text-green-500">{adminStats.approvedCount}</h4></div>
           </div>
           <div className="bg-slate-900 rounded-[2.5rem] border border-slate-800 overflow-hidden shadow-2xl">
              <table className="w-full text-left">
                <thead className="bg-black/40 text-slate-500 text-[10px] font-black uppercase tracking-widest border-b border-slate-800">
                  <tr><th className="p-6">Provider</th><th className="p-6">Type</th><th className="p-6">Status</th><th className="p-6">Doc</th><th className="p-6 text-right">Actions</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {adminRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition">
                      <td className="p-6 font-black text-xs uppercase">{req.userName}</td>
                      <td className="p-6 text-slate-400 text-xs italic">{req.type}</td>
                      <td className="p-6"><span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase ${req.status === 'Approved' ? 'bg-green-500/10 text-green-500' : 'bg-yellow-500/10 text-yellow-500'}`}>{req.status}</span></td>
                      <td className="p-6 font-mono text-[10px] text-blue-400">{req.documentUrl}</td>
                      <td className="p-6 text-right space-x-2">
                        <button onClick={() => updateRequestStatus(req._id, 'Approved')} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[9px] font-black">APPROVE</button>
                        <button onClick={() => updateRequestStatus(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-4 py-2 rounded-xl text-[9px] font-black border border-red-500/20">REJECT</button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // ==========================================
  // VIEW: USER DASHBOARD (SERVICES & TRACKING)
  // ==========================================
  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-white p-4 shadow-sm flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
        <div className="flex gap-4">
           <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'text-slate-400'}`}>Services</button>
           <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white shadow-lg shadow-blue-100' : 'text-slate-400'}`}>Tracking</button>
           <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 p-2"><LogOut size={20}/></button>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto">
        {activeTab === 'services' ? (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase tracking-tighter">Available Services</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map(t => (
                <div key={t} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition">
                   <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-6"><FileText/></div>
                   <h3 className="text-xl font-bold mb-4 tracking-tight leading-tight">{t}</h3>
                   <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl text-[10px] font-black uppercase italic tracking-widest hover:bg-blue-600 transition">Apply Now</button>
                </div>
              ))}
            </div>
            {/* CONTACT SUPPORT */}
            <div className="mt-16 bg-blue-600 rounded-[3rem] p-12 text-white flex flex-col md:flex-row justify-between items-center shadow-2xl shadow-blue-200">
               <div><h3 className="text-2xl font-black uppercase italic tracking-tighter">Need Assistance?</h3><p className="font-medium opacity-80">Our support team is available 24/7 for credentialing help.</p></div>
               <button className="bg-white text-blue-600 px-8 py-4 rounded-2xl font-black mt-6 md:mt-0 flex items-center gap-2 hover:scale-105 transition"><MessageCircle/> Contact Support</button>
            </div>
          </div>
        ) : (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase tracking-tighter underline underline-offset-8">Application Status</h2>
            <div className="space-y-4">
               {userRequests.map((r, i) => (
                 <div key={r._id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex justify-between items-center shadow-sm hover:shadow-md transition group">
                    <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-slate-900 rounded-2xl flex flex-col items-center justify-center text-white group-hover:bg-blue-600 transition-colors">
                            <span className="text-[8px] font-black opacity-40 uppercase">REQ</span>
                            <span className="text-lg font-black italic">0{i+1}</span>
                        </div>
                        <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter italic">{r.type}</h3><p className="text-slate-400 font-bold text-[9px] uppercase tracking-widest mt-1"><Clock size={10} className="inline mr-1"/> Submitted: {new Date(r.submittedDate).toLocaleDateString()}</p></div>
                    </div>
                    <div className={`px-6 py-2 rounded-full text-[10px] font-black uppercase ${r.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>{r.status}</div>
                 </div>
               ))}
               {userRequests.length === 0 && <div className="p-20 text-center text-slate-300 font-black uppercase italic border-2 border-dashed rounded-[3rem]">No Applications Found</div>}
            </div>
          </div>
        )}
      </main>

      {/* --- SUBMISSION MODAL (FILE PICKER) --- */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-8 text-blue-600 uppercase italic">New Credentialing Request</h2>
            <form onSubmit={handleApplicationSubmit} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none outline-none"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License / NPI ID" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none outline-none" required />
              <div onClick={handleFileUpload} className="p-10 bg-blue-50 border-2 border-dashed border-blue-200 rounded-[2rem] cursor-pointer text-center group hover:bg-blue-100 transition">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={32}/>
                <p className="text-[10px] font-black uppercase text-blue-600 tracking-tighter">{selectedFileName ? `SELECTED: ${selectedFileName}` : "Select System Document"}</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 hover:bg-blue-700 transition mt-4 uppercase italic">Confirm & Submit</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full text-slate-300 font-bold hover:text-red-500 transition mt-2">Cancel Submission</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
